var e=[{id:`L2_1`,type:`dialog`,speaker:`PAWN_REPLACER_HUMAN_BOSS`,text:{KOREA:`이...... 무슨 정신 나간 힘이?!`,JPN:`な……何て力だ！？`,ENG:`Such power... It’s impossible!`,TWN:`這……什麼瘋狂的力量？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`PAWN_REPLACER_HUMAN_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ORCA_RSEVEN_NULL_NULL`,text:{KOREA:`침식체는!! 전부 죽인다!!!`,JPN:`侵食体は！！　全部殺す！！！`,ENG:`Corrupt Object... Must kill all!!`,TWN:`侵蝕體！！殺光它們！！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`REPLACER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`PAWN_REPLACER_HUMAN_BOSS`,text:{KOREA:`왜, 왜 죽지도 않는 거냐?! 이 괴물 같은 놈이!!`,JPN:`な、なぜ死なないんだ！？　この化け物が！！`,ENG:`W-why won’t you die?! You monster!`,TWN:`為什麼連死都死不了？！ 妳這個怪物一樣的傢伙！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`PAWN_REPLACER_HUMAN_BOSS`,face:`UNIT_IDLE`},R:{char_id:`REPLACER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`ORCA_RSEVEN_NULL_NULL`,text:{KOREA:`닥쳐! 더러운 침식체!!`,JPN:`黙れ！　汚らわしい侵食体め！！`,ENG:`Shut up! Dirty Corrupt Object!!`,TWN:`閉嘴！骯髒的侵蝕體！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:{char_id:`REPLACER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`ORCA_RSEVEN_NULL_NULL`,text:{KOREA:`크아아아아아!!`,JPN:`くあああああっ！！`,ENG:`Groarr!!`,TWN:`唔啊啊啊啊啊！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`},R:{char_id:`REPLACER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`이, 이거 괜찮은 거 맞아? 쟤 눈이 맛이 갔다고!`,JPN:`こ、これ大丈夫なのか？　あいつ、目がヤバいぞ？`,ENG:`Y-you sure about this? She got all googly-eyed!`,TWN:`她、她沒事？她眼睛看不到了！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`ORCA_RSEVEN_NULL_NULL`,text:{KOREA:`침식체는 전부 죽인다!!!`,JPN:`侵食体は全部殺す！！！`,ENG:`Must kill all Corrupt Object!`,TWN:`殺光侵蝕體！！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`제기랄! 우리도 못 알아보는 것 같은데?`,JPN:`クソ！　俺たちのことも見分けがつかねえみたいだ！`,ENG:`Damn it! I don’t think she even recognizes us now!`,TWN:`天哪！她好像連我們也認不出來啊！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`사람이 침식되는 모습을 봐서 너무 흥분한 것 같아!`,JPN:`人が侵食していく姿を見て興奮したようだ！`,ENG:`Seeing those people turn probably set her off!`,TWN:`感覺她看到人類被侵蝕的樣子很興奮！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`이대론 완전히 먹혀 버릴 거야!`,JPN:`このままだと、完全に飲み込まれる！`,ENG:`At this rate, the Orca will consume the kid completely!`,TWN:`再這樣會被完全吞噬掉的！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`아까 그거! 이터니움 정제 더 없어?`,JPN:`さっきのあれ！　エタニウムの粉はもう残ってないの？`,ENG:`Hey, that thing from before! Got any more refined Eternium?`,TWN:`喂！沒有永恆之金晶體了嗎？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`하나 만들어 두긴 했는데...... 일단 붙잡아!!`,JPN:`もう一つ作っておいたが……とりあえず動きを止めろ！！`,ENG:`I did make another shot... But hold onto her first!`,TWN:`之前做了一個……先抓住她！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L35_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`아, 젠장! 또냐!!`,JPN:`あ、クソ！　またかよ！！`,ENG:`Ugh, damn it! Not again!`,TWN:`真是的，又來了！！`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L36_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`젠장! 죽기 아니면 까무러치기지!!`,JPN:`ちくしょう！　死ぬ気でいくよ！！`,ENG:`Ah, screw it! What's the worst that could happen!`,TWN:`該死！不想死的話就乖乖昏過去！！`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};